mapper.select:
SELECT * FROM user_coupon
WHERE user_id = #{userId}
AND status = #{status}
ORDER BY claimed_at DESC

mapper.update:
UPDATE user_coupon
SET status = 1, used_order_id = #{orderId}, used_at = #{usedAt}
WHERE id = #{id} AND status = 0

UPDATE user_coupon
SET status = 2
WHERE status = 0 AND expired_at < #{now}

